{
  "command": "psql -h 127.0.0.1 -U user -d crm_support -c \"SELECT DISTINCT field__c FROM casehistory__c LIMIT 20;\"",
  "description": "Check field values"
}

{
  "command": "psql -h 127.0.0.1 -U user -d crm_support -c \"SELECT * FROM casehistory__c WHERE field__c='Owner Assignment' LIMIT 10;\"",
  "description": "Check owner assignment records"
}

{
  "command": "psql -h 127.0.0.1 -U user -d crm_support -c \"SELECT COUNT(*) FROM casehistory__c WHERE field__c='Owner Assignment' AND oldvalue__c IS NOT NULL AND oldvalue__c <> '';\"",
  "description": "Check non-null oldvalue"
}

{
  "command": "psql -h 127.0.0.1 -U user -d crm_support -c \"SELECT caseid__c, COUNT(*) FROM casehistory__c WHERE field__c='Owner Assignment' GROUP BY caseid__c HAVING COUNT(*) > 1 LIMIT 5;\"",
  "description": "Check cases with multiple owners"
}

{
  "command": "psql -h 127.0.0.1 -U user -d crm_support -c \"SELECT * FROM casehistory__c WHERE caseid__c='500Wt00000DDz6FIAT' ORDER BY createddate;\"",
  "description": "Check one case with multiple owners"
}

{
  "command": "psql -h 127.0.0.1 -U user -d crm_support -c "
-- All cases with multiple owner assignments
SELECT caseid__c, createddate, oldvalue__c, newvalue__c
FROM casehistory__c
WHERE field__c='Owner Assignment'
  AND caseid__c IN (
    SELECT caseid__c FROM casehistory__c WHERE field__c='Owner Assignment' GROUP BY caseid__c HAVING COUNT(*) > 1
  )
ORDER BY caseid__c, createddate;
"",
  "description": "All multi-owner cases"
}
